#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=1e7+7;

int x,y;
ll a[N],mxdep,ans[N];

bool dfs(int dep,ll x,ll y,ll last){
    if(x==0){
        //for(int i=1;i<=mxdep;i++)
        //    printf("%d ",a[i]);
        //puts("");
        if(!ans[mxdep] || ans[mxdep]>a[mxdep])
            for(int i=1;i<=mxdep;i++)
                ans[i]=a[i];
        return 1;
    }
    if(dep>mxdep)
        return 0;
    bool res=0;
    for(ll w=max(last+1,(y+x-1)/x);w<=min(10000000ll,1LL*(mxdep-dep+1)*y/x);w++){
        ll xx=x*w-y,yy=y*w,gcd=__gcd(xx,yy);
        a[dep]=w;
        //printf("%d/%d - %d/%d = %d/%d\n",x,y,1,w,xx/gcd,yy/gcd);
        if(dfs(dep+1,xx/gcd,yy/gcd,w))
            res=1;
    }
    return res;
}

int main(){
    scanf("%d%d",&x,&y);
    for(mxdep=1;;mxdep++)
        if(dfs(1,x/__gcd(x,y),y/__gcd(x,y),0))
            break;
    for(int i=1;i<=mxdep;i++)
        printf("%d ",ans[i]);
    return 0;
}
